### Performance Tests

```rust
#[test]
fn test_10k_lines_performance() {
    let mut log = LogViewer::new(10_000);
    let start = Instant::now();
    for i in 0..10_000 {
        log.push(format!("Log line {} with some content", i));
    }
    assert!(start.elapsed().as_millis() < 100, "Push should be < 100ms for 10k lines");

    // Render should be O(visible_lines)
    let area = Rect::new(0, 0, 120, 40);
    let mut buf = Buffer::empty(area);
    let mut state = LogViewerState::default();
    let start = Instant::now();
    for _ in 0..60 { log.render(area, &mut buf, &mut state); }
    assert!(start.elapsed().as_secs() < 1, "60 renders should be < 1 second");
}
